python3 -c "import re,sys; t=open('candidate-inventory.md').read(); sections=re.split(r'(?=###\s+CAND-\d+:)', t)[1:]; errors=[]

def find(sec,key):
    m=re.search(r'(?im)^\s*[-*]?\s*'+key+r'\s*:\s*(\d+)', sec)
    return int(m.group(1)) if m else None
for sec in sections:
    title=sec.splitlines()[0]
    ui=find(sec,'user_impact'); lk=find(sec,'likelihood'); rc=find(sec,'recoverability'); sf=find(sec,'safety'); rh=find(sec,'reach')
    if None in (ui,lk,rc,sf,rh): errors.append((title,'missing dim')); continue
    expected=3*sf+3*ui+2*lk+2*rc+1*rh
    m=re.search(r'(?im)^\s*[-*]?\s*overall\s*:\s*(\d+)\s*/\s*33', sec)
    if not m or int(m.group(1))!=expected: errors.append((title,f'overall {m and m.group(1)} != expected {expected}'))
    hi=re.search(r'(?im)^\s*[-*]?\s*high_impact\s*:\s*(yes|no)', sec)
    if not hi: errors.append((title,'missing high_impact'))
    else:
        want='yes' if (expected>=18 or sf==3) else 'no'
        if hi.group(1).lower()!=want: errors.append((title,f'high_impact {hi.group(1)} != {want}'))
if errors:
    for e in errors: print('score error:', e, file=sys.stderr)
    sys.exit(1)"

python3 -c "import re,os,sys; t=open('candidate-inventory.md').read(); sections=re.split(r'(?=###\s+CAND-\d+:)', t)[1:]; errors=[]

for sec in sections:
    title=sec.splitlines()[0]
    m=re.search(r'(?im)^\s*[-*]?\s*coverage\s*:\s*(.*)$', sec)
    if not m: errors.append((title,'no coverage line')); continue
    line=m.group(1)
    if 'no direct coverage' in line.lower(): continue
    paths=re.findall(r'tests/[A-Za-z0-9_./-]+\.(?:ts|mjs)', line)
    if not paths: errors.append((title,'coverage cites neither test file nor no-direct-coverage')); continue
    for p in paths:
        if not os.path.exists(p): errors.append((title,f'test file missing: {p}'))
if errors:
    for e in errors: print('coverage error:', e, file=sys.stderr)
    sys.exit(1)"
